'use client';

import { mergeProps } from '@base-ui/react/merge-props';
import { Tooltip as BaseTooltip } from '@base-ui/react/tooltip';
import { cloneElement, type FC, isValidElement, use, useCallback, useMemo } from 'react';
import { mergeRefs } from 'react-merge-refs';

import { useNativeButton } from '@/hooks/useNativeButton';

import { TooltipGroupHandleContext } from './groupContext';
import { type TooltipProps } from './type';
import { useMergedTooltipProps } from './useMergedTooltipProps';

const DEFAULT_OPEN_DELAY = 400;
const DEFAULT_CLOSE_DELAY = 100;

export const TooltipInGroup: FC<TooltipProps> = ({
  children,
  ref: refProp,
  arrow,
  className,
  classNames,
  closeDelay,
  defaultOpen,
  disabled: disabledProp,
  getPopupContainer,
  hotkey,
  hotkeyProps,
  mouseEnterDelay,
  mouseLeaveDelay,
  onOpenChange,
  open,
  openDelay,
  placement,
  popupContainer,
  popupProps,
  portalProps,
  positionerProps,
  standalone: _standalone,
  styles,
  title,
  triggerProps: triggerPropsProp,
  zIndex,
  ...restProps
}) => {
  const tooltipProps = useMemo(
    () => ({
      arrow,
      className,
      classNames,
      closeDelay,
      defaultOpen,
      disabled: disabledProp,
      getPopupContainer,
      hotkey,
      hotkeyProps,
      mouseEnterDelay,
      mouseLeaveDelay,
      onOpenChange,
      open,
      openDelay,
      placement,
      popupContainer,
      popupProps,
      portalProps,
      positionerProps,
      styles,
      title,
      triggerProps: triggerPropsProp,
      zIndex,
    }),
    [
      arrow,
      className,
      classNames,
      closeDelay,
      defaultOpen,
      disabledProp,
      getPopupContainer,
      hotkey,
      hotkeyProps,
      mouseEnterDelay,
      mouseLeaveDelay,
      onOpenChange,
      open,
      openDelay,
      placement,
      popupContainer,
      popupProps,
      portalProps,
      positionerProps,
      styles,
      title,
      triggerPropsProp,
      zIndex,
    ],
  );

  const group = use(TooltipGroupHandleContext);
  const item = useMergedTooltipProps(tooltipProps);

  const resolvedOpenDelay = useMemo(() => {
    if (item.openDelay !== undefined) return item.openDelay;
    if (item.mouseEnterDelay !== undefined) return item.mouseEnterDelay * 1000;
    return DEFAULT_OPEN_DELAY;
  }, [item.mouseEnterDelay, item.openDelay]);

  const resolvedCloseDelay = useMemo(() => {
    if (item.closeDelay !== undefined) return item.closeDelay;
    if (item.mouseLeaveDelay !== undefined) return item.mouseLeaveDelay * 1000;
    return DEFAULT_CLOSE_DELAY;
  }, [item.closeDelay, item.mouseLeaveDelay]);

  const disabled = Boolean(item.disabled);

  const { isNativeButtonTriggerElement } = useNativeButton({
    children,
  });

  const childElement = isValidElement(children) ? children : null;

  const renderTrigger = useCallback(
    (renderProps: unknown) => {
      // Base UI's trigger props include `type="button"` by default.
      // If we render into a non-<button> element, that prop is invalid and can warn.
      const resolvedProps = (() => {
        if (isNativeButtonTriggerElement) return renderProps as any;
        // eslint-disable-next-line unused-imports/no-unused-vars
        const { type, ref: triggerRef, ...triggerRest } = renderProps as any;
        return triggerRest;
      })();

      const mergedProps = mergeProps(restProps, (childElement as any).props, resolvedProps);
      return cloneElement(childElement as any, {
        ...mergedProps,
        ref: mergeRefs([(childElement as any).ref, (renderProps as any).ref, refProp]),
      });
    },
    [childElement, isNativeButtonTriggerElement, refProp, restProps],
  );

  // Don't render trigger behavior if no content

  if (item.title == null && !item.hotkey) {
    return children as any;
  }

  const triggerProps = {
    closeDelay: resolvedCloseDelay,
    delay: resolvedOpenDelay,
    disabled,
    payload: item,
  };

  if (childElement) {
    return (
      <BaseTooltip.Trigger handle={group ?? undefined} {...triggerProps} render={renderTrigger} />
    );
  }

  return (
    <BaseTooltip.Trigger handle={group ?? undefined} {...triggerProps} ref={refProp}>
      {children}
    </BaseTooltip.Trigger>
  );
};

TooltipInGroup.displayName = 'TooltipInGroup';
